# ① ANIMATED WHALE WIDGET
# ══════════════════════════════════════════════════════════════════════════════
class AnimatedWhaleWidget(QWidget):
    """
    Self-contained animated whale mascot.
    Animations running simultaneously:
      • Float bob     — sinusoidal vertical drift
      • Glow pulse    — cyan aura breathes in/out
      • Record spin   — turntable platter rotates
      • Scanlines     — retro CRT scanline overlay
      • Particle ring — tiny orbiting dots
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setFixedSize(220, 220)
        self.setAttribute(Qt.WA_TranslucentBackground)

        # Load whale
        raw = _px_from_b64(WHALE_B64_160)
        self._whale = _circle_crop(raw)

        # Animation state
        self._t = 0.0          # master time (radians)
        self._record_angle = 0.0
        self._particles = [
            {"angle": i * (360/12), "radius": 90, "speed": 0.8 + random.random()*0.6,
             "size": 2 + random.random()*2, "color": random.choice(["cyan","magenta","yellow"])}
            for i in range(12)
        ]

        self._timer = QTimer(self)
        self._timer.timeout.connect(self._tick)
        self._timer.start(16)  # ~60 fps

    def _tick(self):
        self._t += 0.04
        self._record_angle = (self._record_angle + 2.5) % 360
        for p in self._particles:
            p["angle"] = (p["angle"] + p["speed"]) % 360
        self.update()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.Antialiasing)
        cx, cy = self.width() // 2, self.height() // 2

        t = self._t
        bob_y = math.sin(t * 0.8) * 6          # ±6px vertical float
        glow_alpha = int(80 + math.sin(t) * 50) # 30–130 pulsing glow
        glow_r = 85 + math.sin(t * 1.2) * 8    # pulsing radius

        # ── Outer glow rings (multiple layers) ──
        for i, (r_extra, alpha_div) in enumerate([(20,4),(12,3),(5,2)]):
            g = QRadialGradient(cx, cy + bob_y, glow_r + r_extra)
            g.setColorAt(0,   QColor(0, 229, 255, glow_alpha // alpha_div))
            g.setColorAt(0.6, QColor(0, 183, 212, glow_alpha // (alpha_div*2)))
            g.setColorAt(1,   QColor(0, 0, 0, 0))
            painter.setBrush(QBrush(g))
            painter.setPen(Qt.NoPen)
            r = int(glow_r + r_extra)
            painter.drawEllipse(cx - r, int(cy + bob_y) - r, r*2, r*2)

        # ── Spinning record / turntable platter ──
        self._draw_record(painter, cx, cy + bob_y + 55, 38, self._record_angle)

        # ── Cyan ring border around whale ──
        ring_r = 78
        ring_pen = QPen(QColor(0, 229, 255, 160), 2)
        ring_pen.setStyle(Qt.DashLine)
        ring_pen.setDashOffset(self._record_angle / 5)
        painter.setPen(ring_pen)
        painter.setBrush(Qt.NoBrush)
        painter.drawEllipse(
            int(cx - ring_r), int(cy + bob_y - ring_r),
            ring_r*2, ring_r*2
        )

        # ── Inner filled circle (whale bg) ──
        inner_r = 72
        bg_grad = QRadialGradient(cx, cy + bob_y, inner_r)
        bg_grad.setColorAt(0, QColor("#111820"))
        bg_grad.setColorAt(1, QColor("#0a0e14"))
        painter.setBrush(QBrush(bg_grad))
        painter.setPen(Qt.NoPen)
        painter.drawEllipse(
            int(cx - inner_r), int(cy + bob_y - inner_r),
            inner_r*2, inner_r*2
        )

        # ── Draw whale pixmap (bobbing) ──
        pw, ph = self._whale.width(), self._whale.height()
        painter.drawPixmap(
            int(cx - pw//2),
            int(cy + bob_y - ph//2),
            self._whale
        )

        # ── Scanline overlay ──
        painter.setCompositionMode(QPainter.CompositionMode_SourceOver)
        scan_pen = QPen(QColor(0, 0, 0, 25), 1)
        painter.setPen(scan_pen)
        clip_path = QPainterPath()
        clip_path.addEllipse(cx - inner_r, cy + bob_y - inner_r, inner_r*2, inner_r*2)
        painter.setClipPath(clip_path)
        for y in range(int(cy + bob_y - inner_r), int(cy + bob_y + inner_r), 3):
            painter.drawLine(int(cx - inner_r), y, int(cx + inner_r), y)
        painter.setClipping(False)

        # ── Orbiting particles ──
        for p in self._particles:
            rad = math.radians(p["angle"])
            px_x = cx + math.cos(rad) * p["radius"]
            px_y = cy + bob_y + math.sin(rad) * p["radius"] * 0.35
            color = C[p["color"]]
            alpha = int(150 + math.sin(t + p["angle"]) * 80)
            c = QColor(color)
            c.setAlpha(alpha)
            painter.setBrush(QBrush(c))
            painter.setPen(Qt.NoPen)
            s = p["size"]
            painter.drawEllipse(QRectF(px_x - s, px_y - s, s*2, s*2))

        # ── Status text below ──
        painter.setClipping(False)
        font = QFont("Courier New", 9)
        painter.setFont(font)
        painter.setPen(QPen(C["cyan"]))
        status = "♪ DJ WHALE ONLINE ♪"
        fm = QFontMetrics(font)
        tw = fm.horizontalAdvance(status)
        painter.drawText(int(cx - tw//2), int(cy + bob_y + 100), status)

        painter.end()

    def _draw_record(self, painter, cx, cy, r, angle):
        """Draw a spinning vinyl record."""
        # Outer black platter
        painter.setBrush(QBrush(QColor("#111111")))
        painter.setPen(QPen(QColor("#333333"), 1))
        painter.drawEllipse(QPoint(int(cx), int(cy)), r, r//3)

        # Grooves (rotated lines)
        for i in range(5):
            groove_r = int(r * (0.4 + i * 0.12))
            alpha = 60 - i * 8
            painter.setPen(QPen(QColor(80, 80, 80, alpha), 0.5))
            painter.setBrush(Qt.NoBrush)
            painter.drawEllipse(QPoint(int(cx), int(cy)), groove_r, groove_r//3)

        # Center label (yellow, spinning)
        label_r = int(r * 0.28)
        cg = QConicalGradient(cx, cy, angle)
        cg.setColorAt(0,   QColor("#e8ff00"))
        cg.setColorAt(0.5, QColor("#00b8d4"))
        cg.setColorAt(1,   QColor("#e8ff00"))
        painter.setBrush(QBrush(cg))
        painter.setPen(Qt.NoPen)
        painter.drawEllipse(QPoint(int(cx), int(cy)), label_r, label_r//3)

        # Center hole
        painter.setBrush(QBrush(QColor("#0a0e14")))
        painter.drawEllipse(QPoint(int(cx), int(cy)), 3, 2)


