class ScoreBar(QWidget):
    """Horizontal relevance score bar."""
    def __init__(self, score: float, parent=None):
        super().__init__(parent)
        self.score = score
        self.setFixedSize(120, 6)

    def paintEvent(self, event):
        p = QPainter(self)
        p.setRenderHint(QPainter.Antialiasing)
        # Track
        p.setBrush(QBrush(QColor("#1a2535")))
        p.setPen(Qt.NoPen)
        p.drawRoundedRect(0, 0, self.width(), self.height(), 3, 3)
        # Fill
        fill_w = int(self.width() * self.score)
        if fill_w > 0:
            grad = QLinearGradient(0, 0, fill_w, 0)
            if self.score > 0.85:
                grad.setColorAt(0, QColor("#00b8d4"))
                grad.setColorAt(1, QColor("#00ff88"))
            elif self.score > 0.7:
                grad.setColorAt(0, QColor("#00b8d4"))
                grad.setColorAt(1, QColor("#ff8800"))
            else:
                grad.setColorAt(0, QColor("#3a6070"))
                grad.setColorAt(1, QColor("#ff8800"))
            p.setBrush(QBrush(grad))
            p.drawRoundedRect(0, 0, fill_w, self.height(), 3, 3)
        p.end()


class ResultCard(QWidget):
    """Single RAG result card."""
    def __init__(self, data: dict, index: int, parent=None):
        super().__init__(parent)
        self.setObjectName("ResultCard")
        self.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Minimum)
        self.setCursor(QCursor(Qt.PointingHandCursor))
        self._hovered = False

        self.setStyleSheet("""
            #ResultCard {
                background: #0d1520;
                border: 1px solid #1a2535;
                border-radius: 8px;
            }
        """)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(14, 10, 14, 10)
        layout.setSpacing(6)

        # ── Header row ──
        header = QHBoxLayout()
        header.setSpacing(8)

        # Index badge
        idx_lbl = QLabel(f"#{index+1:02d}")
        idx_lbl.setFont(QFont("Courier New", 10, QFont.Bold))
        idx_lbl.setStyleSheet("color: #3a6070; background: transparent;")
        idx_lbl.setFixedWidth(32)
        header.addWidget(idx_lbl)

        # Source file
        src = QLabel(data["source"])
        src.setFont(QFont("Courier New", 11))
        src.setStyleSheet("color: #00b8d4; background: transparent;")
        header.addWidget(src, 1)

        # Method chip
        mc, mbg = METHOD_COLORS[data["method"]]
        method_chip = QLabel(f" {data['method'].upper()} ")
        method_chip.setFont(QFont("Courier New", 9, QFont.Bold))
        method_chip.setStyleSheet(f"color: {mc}; background: {mbg}; border: 1px solid {mc}; border-radius: 4px; padding: 0 2px;")
        header.addWidget(method_chip)

        layout.addLayout(header)

        # ── Score row ──
        score_row = QHBoxLayout()
        score_row.setSpacing(8)
        score_lbl = QLabel(f"relevance  {data['score']:.3f}")
        score_lbl.setFont(QFont("Courier New", 10))
        score_lbl.setStyleSheet("color: #3a6070; background: transparent;")
        score_row.addWidget(score_lbl)
        score_row.addWidget(ScoreBar(data["score"]))
        chunk_lbl = QLabel(f"chunk {data['chunk']}/{data['total']}  ·  {data['tokens']} tokens")
        chunk_lbl.setFont(QFont("Courier New", 9))
        chunk_lbl.setStyleSheet("color: #2a4050; background: transparent;")
        score_row.addWidget(chunk_lbl)
        score_row.addStretch()
        layout.addLayout(score_row)

        # ── Text preview ──
        sep = QFrame()
        sep.setFixedHeight(1)
        sep.setStyleSheet("background: #1a2535;")
        layout.addWidget(sep)

        text_lbl = QLabel(data["text"])
        text_lbl.setFont(QFont("Noto Sans SC", 11) if True else QFont("Arial", 11))
        text_lbl.setWordWrap(True)
        text_lbl.setStyleSheet("color: #8ab4c8; background: transparent; line-height: 1.6;")
        text_lbl.setTextFormat(Qt.PlainText)
        layout.addWidget(text_lbl)

    def enterEvent(self, e):
        self._hovered = True
        self.setStyleSheet("""
            #ResultCard {
                background: #111d2a;
                border: 1px solid #00b8d4;
                border-radius: 8px;
            }
        """)

    def leaveEvent(self, e):
        self._hovered = False
        self.setStyleSheet("""
            #ResultCard {
                background: #0d1520;
                border: 1px solid #1a2535;
                border-radius: 8px;
            }
        """)


